CREATE TABLE IF NOT EXISTS admins (id TEXT PRIMARY KEY, password_hash TEXT NOT NULL, password_salt TEXT NOT NULL, must_change_password INTEGER NOT NULL DEFAULT 1, failed_attempts INTEGER NOT NULL DEFAULT 0, locked_until TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS admin_sessions (id TEXT PRIMARY KEY, admin_id TEXT NOT NULL, token_hash TEXT NOT NULL UNIQUE, csrf_token TEXT NOT NULL, expires_at TEXT NOT NULL, last_seen_at TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS store_settings (id TEXT PRIMARY KEY, store_name TEXT NOT NULL, description TEXT NOT NULL, phone TEXT NOT NULL, email TEXT NOT NULL, notification_email TEXT NOT NULL, instagram_url TEXT, logo_url TEXT, hero_url TEXT, currency TEXT NOT NULL DEFAULT 'JPY', tax_label TEXT NOT NULL DEFAULT '税込', minimum_order_amount INTEGER NOT NULL DEFAULT 800, payment_methods TEXT NOT NULL, order_status TEXT NOT NULL DEFAULT 'OPEN', completion_message TEXT NOT NULL, privacy_policy TEXT NOT NULL, terms TEXT NOT NULL, allergy_notice TEXT NOT NULL, preparation_minutes INTEGER NOT NULL DEFAULT 30, booking_days INTEGER NOT NULL DEFAULT 14, session_minutes INTEGER NOT NULL DEFAULT 480, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS business_locations (id TEXT PRIMARY KEY, name TEXT NOT NULL, address TEXT NOT NULL, map_url TEXT NOT NULL, is_active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS business_schedules (id TEXT PRIMARY KEY, day_of_week INTEGER NOT NULL, location_id TEXT NOT NULL, opens_at TEXT NOT NULL, closes_at TEXT NOT NULL, pickup_interval_minutes INTEGER NOT NULL, slot_capacity INTEGER NOT NULL, cutoff_minutes INTEGER NOT NULL, same_day_allowed INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS special_business_days (id TEXT PRIMARY KEY, business_date TEXT NOT NULL, is_closed INTEGER NOT NULL, location_id TEXT, opens_at TEXT, closes_at TEXT, notice TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS categories (id TEXT PRIMARY KEY, name TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, sort_order INTEGER NOT NULL, is_published INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS menu_items (id TEXT PRIMARY KEY, category_id TEXT NOT NULL, name TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, description TEXT NOT NULL, price INTEGER NOT NULL, ingredients TEXT NOT NULL, allergens TEXT NOT NULL, spiciness INTEGER NOT NULL DEFAULT 0, preparation_minutes INTEGER NOT NULL DEFAULT 10, image_url TEXT, stock INTEGER, max_per_order INTEGER NOT NULL DEFAULT 10, is_published INTEGER NOT NULL DEFAULT 1, is_sold_out INTEGER NOT NULL DEFAULT 0, is_recommended INTEGER NOT NULL DEFAULT 0, is_new INTEGER NOT NULL DEFAULT 0, sort_order INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS menu_item_images (id TEXT PRIMARY KEY, menu_item_id TEXT NOT NULL, object_key TEXT NOT NULL, mime_type TEXT NOT NULL, width INTEGER, height INTEGER, sort_order INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS option_groups (id TEXT PRIMARY KEY, menu_item_id TEXT NOT NULL, name TEXT NOT NULL, is_required INTEGER NOT NULL, min_selections INTEGER NOT NULL, max_selections INTEGER NOT NULL, sort_order INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS option_choices (id TEXT PRIMARY KEY, option_group_id TEXT NOT NULL, name TEXT NOT NULL, additional_price INTEGER NOT NULL, is_sold_out INTEGER NOT NULL DEFAULT 0, sort_order INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS pickup_slots (id TEXT PRIMARY KEY, location_id TEXT NOT NULL, starts_at TEXT NOT NULL, capacity INTEGER NOT NULL, reserved_count INTEGER NOT NULL DEFAULT 0, is_paused INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS orders (id TEXT PRIMARY KEY, order_number TEXT NOT NULL UNIQUE, verification_hash TEXT NOT NULL, idempotency_key TEXT NOT NULL UNIQUE, customer_name TEXT NOT NULL, customer_name_kana TEXT NOT NULL, phone TEXT NOT NULL, email TEXT NOT NULL, pickup_at TEXT NOT NULL, pickup_location_id TEXT NOT NULL, pickup_location_name TEXT NOT NULL, payment_method TEXT NOT NULL, status TEXT NOT NULL, subtotal INTEGER NOT NULL, total INTEGER NOT NULL, customer_note TEXT, allergy_declaration TEXT, admin_note TEXT, email_status TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS orders_pickup_status_idx ON orders (pickup_at, status);
CREATE TABLE IF NOT EXISTS order_items (id TEXT PRIMARY KEY, order_id TEXT NOT NULL, menu_item_id TEXT, item_name TEXT NOT NULL, unit_price INTEGER NOT NULL, quantity INTEGER NOT NULL, line_total INTEGER NOT NULL, note TEXT, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS order_item_options (id TEXT PRIMARY KEY, order_item_id TEXT NOT NULL, group_name TEXT NOT NULL, choice_name TEXT NOT NULL, additional_price INTEGER NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS announcements (id TEXT PRIMARY KEY, title TEXT NOT NULL, body TEXT NOT NULL, severity TEXT NOT NULL, starts_at TEXT NOT NULL, ends_at TEXT, is_published INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS email_deliveries (id TEXT PRIMARY KEY, order_id TEXT, type TEXT NOT NULL, recipient_masked TEXT NOT NULL, subject TEXT NOT NULL, text_body TEXT NOT NULL, html_body TEXT NOT NULL, status TEXT NOT NULL, attempts INTEGER NOT NULL, last_error TEXT, sent_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS audit_logs (id TEXT PRIMARY KEY, admin_id TEXT, action TEXT NOT NULL, target_type TEXT NOT NULL, target_id TEXT, summary TEXT NOT NULL, ip_hash TEXT, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS rate_limits (id TEXT PRIMARY KEY, scope TEXT NOT NULL, identity_hash TEXT NOT NULL, window_started_at TEXT NOT NULL, count INTEGER NOT NULL, expires_at TEXT NOT NULL);
